"use client"

import { useEffect, useState } from "react"
import { useStore } from "@/store"
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card"
import { api } from "@/lib/api"
import { FolderKanban, CheckCircle, Clock, Users } from "lucide-react"
import Link from "next/link"

export default function DashboardPage() {
  const { currentOrg, projects } = useStore()
  const [workload, setWorkload] = useState<any[]>([])

  useEffect(() => {
    if (currentOrg) {
      loadWorkload()
    }
  }, [currentOrg])

  const loadWorkload = async () => {
    if (!currentOrg) return
    try {
      const { workload } = await api.getWorkloadAnalysis(currentOrg._id)
      setWorkload(workload)
    } catch (error) {
      console.error("Failed to load workload:", error)
    }
  }

  const totalProjects = projects.length
  const activeProjects = projects.filter((p) => p.status === "active").length

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600">Welcome to {currentOrg?.name || "your workspace"}</p>
      </div>

      <div className="grid md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-100 rounded-lg">
                <FolderKanban className="h-6 w-6 text-blue-600" />
              </div>
              <div>
                <p className="text-2xl font-bold text-gray-900">{totalProjects}</p>
                <p className="text-sm text-gray-500">Total Projects</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-green-100 rounded-lg">
                <CheckCircle className="h-6 w-6 text-green-600" />
              </div>
              <div>
                <p className="text-2xl font-bold text-gray-900">{activeProjects}</p>
                <p className="text-sm text-gray-500">Active Projects</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-purple-100 rounded-lg">
                <Users className="h-6 w-6 text-purple-600" />
              </div>
              <div>
                <p className="text-2xl font-bold text-gray-900">{workload.length}</p>
                <p className="text-sm text-gray-500">Team Members</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-orange-100 rounded-lg">
                <Clock className="h-6 w-6 text-orange-600" />
              </div>
              <div>
                <p className="text-2xl font-bold text-gray-900">
                  {workload.reduce((sum, w) => sum + w.task_count, 0)}
                </p>
                <p className="text-sm text-gray-500">Total Tasks</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle className="text-gray-900">Projects</CardTitle>
          </CardHeader>
          <CardContent>
            {projects.length === 0 ? (
              <p className="text-gray-500 text-sm">No projects yet. Create your first project!</p>
            ) : (
              <div className="space-y-2">
                {projects.slice(0, 5).map((project) => (
                  <Link
                    key={project._id}
                    href={`/dashboard/projects/${project._id}`}
                    className="flex items-center justify-between p-3 rounded-lg hover:bg-gray-50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <FolderKanban className="h-5 w-5 text-gray-400" />
                      <div>
                        <p className="font-medium text-gray-900">{project.name}</p>
                        <p className="text-xs text-gray-500">{project.member_count} members</p>
                      </div>
                    </div>
                    <span className={`text-xs px-2 py-1 rounded font-medium ${
                      project.status === "active" ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-700"
                    }`}>
                      {project.status}
                    </span>
                  </Link>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-gray-900">Team Workload</CardTitle>
          </CardHeader>
          <CardContent>
            {workload.length === 0 ? (
              <p className="text-gray-500 text-sm">No workload data available.</p>
            ) : (
              <div className="space-y-3">
                {workload.map((member) => (
                  <div key={member.user._id} className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center text-sm font-medium">
                      {member.user.name?.charAt(0).toUpperCase()}
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <p className="text-sm font-medium text-gray-900">{member.user.name}</p>
                        <span className={`text-xs px-2 py-0.5 rounded font-medium ${
                          member.status === "overloaded" ? "bg-red-100 text-red-700" :
                          member.status === "balanced" ? "bg-green-100 text-green-700" :
                          "bg-blue-100 text-blue-700"
                        }`}>
                          {member.status}
                        </span>
                      </div>
                      <p className="text-xs text-gray-500">
                        {member.task_count} tasks • {member.estimated_hours}h estimated
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  )
}
